import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import {
  Trash2, Download, Archive, Calendar,
  ShieldCheck, Eye, X, BarChart3, AlignLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────────────── Fetch Vault History ───────────────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data?.data || res.data || []);
    } catch {
      toast.error('VAULT_SYNC_ERROR: UNABLE_TO_REACH_DATABASE');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────────────── Delete Node ───────────────── */
  const handleDelete = useCallback(async (id) => {
    const confirmDelete = window.confirm(
      'This strategy node will be permanently deleted. Continue?'
    );
    if (!confirmDelete) return;

    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success('DATA_PURGE_SUCCESSFUL');
    } catch {
      toast.error('WIPE_FAILURE: DATA_PROTECTED_BY_SYSTEM');
    }
  }, []);

  /* ───────────────── Export PDF ───────────────── */
  const handleDownload = useCallback(async (item) => {
    try {
      const response = await api.post(
        '/portfolio/export',
        item,
        { responseType: 'blob' }
      );

      const blob = new Blob([response.data], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = url;
      link.download = `Finify_Strategy_${item.id}.pdf`;
      document.body.appendChild(link);
      link.click();

      link.remove();
      URL.revokeObjectURL(url);
    } catch {
      toast.error('EXPORT_FAILED: GENERATION_ERROR');
    }
  }, []);

  /* ───────────────── Lock Scroll on Modal ───────────────── */
  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'auto';
    return () => (document.body.style.overflow = 'auto');
  }, [selectedItem]);

  if (loading) {
    return <div style={centerStyle}>SYNCHRONIZING_STRATEGY_VAULT...</div>;
  }

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* ── Header ── */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={40} /> STRATEGY_VAULT
        </h2>
        <div style={vaultBadge}>
          <BarChart3 size={20} />
          {history.length} ACTIVE_NODES
        </div>
      </div>

      {/* ── Cards ── */}
      <div style={listStyle}>
        {history.length === 0 && (
          <div style={emptyState}>
            NO_DATA_FOUND: INITIALIZE_STRATEGY_IN_DASHBOARD
          </div>
        )}

        {history.map(item => (
          <div key={item.id} className="vault-card" style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '30px' }}>
                <span style={dateTag}>
                  <Calendar size={18} />
                  {new Date(item.created_at).toLocaleDateString()}
                </span>
                <span style={riskTag}>
                  <ShieldCheck size={18} />
                  RISK_EXPOSURE: {item.risk_score}
                </span>
              </div>

              <div style={cardActions}>
                <button
                  aria-label="View strategy"
                  style={iconBtn}
                  onClick={() => setSelectedItem(item)}
                >
                  <Eye size={28} />
                </button>

                <button
                  aria-label="Download PDF"
                  style={iconBtn}
                  onClick={() => handleDownload(item)}
                >
                  <Download size={28} />
                </button>

                <button
                  aria-label="Delete strategy"
                  style={deleteBtn}
                  onClick={() => handleDelete(item.id)}
                >
                  <Trash2 size={28} />
                </button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal}</h4>

            <div style={sectionBlock}>
              <p style={labelSmall}>
                <AlignLeft size={14} />
                STRATEGIC_SUMMARY
              </p>
              <div className="markdown-vault">
                <ReactMarkdown>{item.summary}</ReactMarkdown>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* ── Modal ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent(isDark)}>
            <div style={modalHeader(isDark)}>
              <span style={modalId}>
                NODE_DATA // SYNC_ID_{selectedItem.id}
              </span>
              <button
                aria-label="Close modal"
                style={closeBtn(isDark)}
                onClick={() => setSelectedItem(null)}
              >
                <X size={32} />
              </button>
            </div>

            <div style={modalBody(isDark)}>
              <h3 style={modalTitle(isDark)}>
                {selectedItem.goal}
              </h3>

              <p style={modalLabel}>
                <AlignLeft size={18} />
                AGENTIC_RATIONALE
              </p>

              <div className={`markdown-vault ${isDark ? 'markdown-dark' : 'markdown-light'}`}>
                <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* styles remain unchanged */
export default VaultPage;
